    public function parseXmlString(string $xmlString): bool
    {
        $this->errors = [];
        $this->settings = [];

        if (empty(trim($xmlString))) {
            $this->errors[] = 'XML string is empty.';
            return false;
        }

        if (!$this->sanitizeXmlContent($xmlString)) {
            return false;
        }

