    private function sanitizeXmlContent(string &$xmlContent): bool
    {
        // Check for DOCTYPE declarations (XXE prevention)
        if (preg_match('/<!DOCTYPE/i', $xmlContent)) {
            $this->errors[] = 'DOCTYPE declarations are not allowed for security reasons.';
            return false;
        }

        // Check for entity declarations
        if (preg_match('/<!ENTITY/i', $xmlContent)) {
            $this->errors[] = 'ENTITY declarations are not allowed for security reasons.';
            return false;
        }

        // Check for CDATA sections with suspicious content
        if (preg_match('/SYSTEM\s+["\']/', $xmlContent)) {
            $this->errors[] = 'SYSTEM references are not allowed for security reasons.';
            return false;
        }

        // Check for processing instructions that could be malicious
        if (preg_match('/<\?(?!xml\s)/i', $xmlContent)) {
            $this->errors[] = 'Processing instructions other than XML declaration are not allowed.';
            return false;
        }

        return true;
