                $settingValue = (string)($child['value'] ?? '');

                if (!empty($settingKey)) {
                    $fullKey = $prefix ? $prefix . '.' . $settingKey : $settingKey;
                    $this->settings[$fullKey] = $this->castValue($settingValue);
                }
            }
        }
