    private function castValue(string $value)
    {
        if ($value === '') {
            return '';
        }

        // Boolean
        $lowerValue = strtolower($value);
        if ($lowerValue === 'true') {
            return true;
        }
        if ($lowerValue === 'false') {
            return false;
        }
        if ($lowerValue === 'null') {
            return null;
        }

        // Integer
        if (preg_match('/^-?\d+$/', $value) && $value === (string)(int)$value) {
            return (int)$value;
        }

        // Float
        if (is_numeric($value) && strpos($value, '.') !== false) {
            return (float)$value;
        }

        return $value;
